import type { ProjectStoryStatus } from '@motivation/shared';

export function formatProjectStatusLabel(status: ProjectStoryStatus): string {
    if (status === 'in_progress') return 'In progress';
    if (status === 'done') return 'Done';
    if (status === 'superseded') return 'Superseded';
    if (status === 'unknown') return 'Unknown';
    return 'Todo';
}

export function projectStatusClass(status: ProjectStoryStatus): string {
    return `status status--${status.replace('_', '-')}`;
}
